solution: ```class StockPrice {
    unordered_map<int,int> ts2price;
    multiset<int> prices;
    int latestTs = 0;
public:
    StockPrice() {}

    void update(int timestamp, int price) {
        if (ts2price.count(timestamp)) {
            prices.erase(prices.find(ts2price[timestamp]));
        }
        ts2price[timestamp] = price;
        prices.insert(price);
        if (timestamp >= latestTs) latestTs = timestamp;
    }

    int current() {
        return ts2price[latestTs];
    }

    int maximum() {
        return *prices.rbegin();
    }

    int minimum() {
        return *prices.begin();
    }
};
```
